import { useEffect } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuthStore } from '@store/authStore';
import AuthLayout from '@layouts/AuthLayout';
import DashboardLayout from '@layouts/DashboardLayout';
import { PrivateRoute, PublicRoute } from '@routes/PrivateRoute';
import { Toaster } from '@components/ui/toaster';

function App() {
  const { initializeAuth } = useAuthStore();

  useEffect(() => {
    // Initialize auth state from localStorage/token
    initializeAuth();
  }, [initializeAuth]);

  return (
    <>
      <Routes>
        {/* Public routes */}
        <Route element={<PublicRoute />}>
          <Route element={<AuthLayout />}>
            <Route path="/auth/login" lazy={() => import('@modules/auth/pages/LoginPage').then(m => ({ Component: m.default }))} />
            <Route path="/auth/register" lazy={() => import('@modules/auth/pages/RegisterPage').then(m => ({ Component: m.default }))} />
            <Route path="/auth/forgot-password" lazy={() => import('@modules/auth/pages/ForgotPasswordPage').then(m => ({ Component: m.default }))} />
            <Route path="/auth/reset-password" lazy={() => import('@modules/auth/pages/ResetPasswordPage').then(m => ({ Component: m.default }))} />
            <Route path="/auth/verify-email" lazy={() => import('@modules/auth/pages/VerifyEmailPage').then(m => ({ Component: m.default }))} />
            <Route path="/auth/setup-2fa" lazy={() => import('@modules/auth/pages/Setup2FAPage').then(m => ({ Component: m.default }))} />
          </Route>
        </Route>

        {/* Protected routes */}
        <Route element={<PrivateRoute />}>
          <Route element={<DashboardLayout />}>
            {/* Dashboard */}
            <Route path="/dashboard" lazy={() => import('@pages/Dashboard').then(m => ({ Component: m.default }))} />

            {/* Staff Management */}
            <Route path="/staff" lazy={() => import('@modules/staff/pages/StaffList').then(m => ({ Component: m.default }))} />
            <Route path="/staff/:id" lazy={() => import('@modules/staff/pages/StaffDetail').then(m => ({ Component: m.default }))} />
            <Route path="/staff/create" lazy={() => import('@modules/staff/pages/StaffForm').then(m => ({ Component: m.default }))} />

            {/* Attendance */}
            <Route path="/attendance" lazy={() => import('@modules/attendance/pages/AttendanceList').then(m => ({ Component: m.default }))} />
            <Route path="/attendance/check-in" lazy={() => import('@modules/attendance/pages/CheckIn').then(m => ({ Component: m.default }))} />

            {/* Projects */}
            <Route path="/projects" lazy={() => import('@modules/projects/pages/ProjectList').then(m => ({ Component: m.default }))} />
            <Route path="/projects/:id" lazy={() => import('@modules/projects/pages/ProjectDetail').then(m => ({ Component: m.default }))} />

            {/* Tasks */}
            <Route path="/tasks" lazy={() => import('@modules/tasks/pages/TaskList').then(m => ({ Component: m.default }))} />
            <Route path="/tasks/:id" lazy={() => import('@modules/tasks/pages/TaskDetail').then(m => ({ Component: m.default }))} />

            {/* Leave */}
            <Route path="/leave/requests" lazy={() => import('@modules/leave/pages/LeaveRequests').then(m => ({ Component: m.default }))} />
            <Route path="/leave/balance" lazy={() => import('@modules/leave/pages/LeaveBalance').then(m => ({ Component: m.default }))} />

            {/* Settings */}
            <Route path="/settings/profile" lazy={() => import('@pages/Settings/ProfileSettings').then(m => ({ Component: m.default }))} />
            <Route path="/settings/security" lazy={() => import('@pages/Settings/SecuritySettings').then(m => ({ Component: m.default }))} />
            <Route path="/settings/notifications" lazy={() => import('@pages/Settings/NotificationSettings').then(m => ({ Component: m.default }))} />
          </Route>
        </Route>

        {/* Not found */}
        <Route path="/" element={<Navigate to="/dashboard" replace />} />
        <Route path="*" lazy={() => import('@pages/NotFound').then(m => ({ Component: m.default }))} />
      </Routes>

      <Toaster />
    </>
  );
}

export default App;
